diagrams.overall_architecture:
digraph G {
  rankdir=TB;
  node [shape=box, style=filled, fillcolor=lightblue, fontname="Arial"];
  edge [fontname="Arial", fontsize=10];

  RRC [label="eNB RRC\n(Control Plane)"];
  RLC [label="eNB RLC\n(Data Plane)"];
  MAC [label="eNB MAC\n(Scheduler & HARQ)"];
  PHY [label="eNB PHY\n(Baseband)"];

  RRC -> MAC [label="Config (MAC-MainConfig)"];
  MAC -> RRC [label="Events (RACH, RLF)"];
  RLC -> MAC [label="DL Data (MAC-DATA-REQ)"];
  MAC -> RLC [label="UL Data (MAC-DATA-IND)"];
  MAC -> PHY [label="Tx Data & Grants"];
  PHY -> MAC [label="Rx Data, CQI, HARQ"];
}

diagrams.rach_procedure:
digraph RACH {
  rankdir=LR;
  node [shape=box, style=rounded, fontname="Arial"];
  edge [fontname="Arial", fontsize=10];

  UE [label="UE"];
  PHY [label="eNB PHY"];
  MAC [label="eNB MAC"];
  RRC [label="eNB RRC"];

  UE -> PHY [label="Msg1: Preamble"];
  PHY -> MAC [label="PRACH Indication"];

  MAC -> PHY [label="Msg2: RAR (Grant+TA)"];
  PHY -> UE [label="Msg2 (PDSCH)"];

  UE -> PHY [label="Msg3: RRC Conn Req"];
  PHY -> MAC [label="UL TB (Msg3)"];
  MAC -> RRC [label="MAC-RACH-IND"];

  MAC -> PHY [label="Msg4: Contention Res"];
  PHY -> UE [label="Msg4 (PDSCH)"];
}

diagrams.harq_timeline:
digraph HARQ {
  rankdir=LR;
  node [shape=note, style=filled, fillcolor=lightyellow, fontname="Arial"];
  edge [fontname="Arial", fontsize=10];

  SFN0 [label="Subframe n:\neNB Tx PDSCH"];
  SFN4 [label="Subframe n+4:\nUE Tx PUCCH (NACK)"];
  SFN8 [label="Subframe n+8:\neNB Re-Tx PDSCH"];

  SFN0 -> SFN4 [label=" 4ms processing "];
  SFN4 -> SFN8 [label=" 4ms processing "];
}

diagrams.mac_rlc_dl_flow:
